// ============================================================
// Sprint 3.2 – Simulation Payload Generator
// Reads `scenario` from input and generates an array of
// mock banking requests to feed into Phase 1's ingress webhook.
// ============================================================

// Helper: random integer between min and max (inclusive)
const randInt = (min, max) => Math.floor(Math.random() * (max - min + 1)) + min;

// Helper: generate a simple user ID (e.g., USR-123456)
const generateUserId = () => 'USR-' + randInt(100000, 999999).toString();

// Read the scenario from the first item's JSON (or default to STANDARD)
const scenario = $input.first().json.body.scenario || 'STANDARD';

let payloadArray = [];

// ============================================================
// 1. Build the payload array based on scenario
// ============================================================
if (scenario === 'STANDARD') {
  // --- 20 low‑risk transactions with random messages ---
  const messagesPool = ['transfer', 'send money', 'check balance', 'hello', 'pay vendor'];

  for (let i = 0; i < 20; i++) {
    payloadArray.push({
      user_id: generateUserId(),
      amount: randInt(5000, 8000000),   // 5k – 8M UZS
      message: messagesPool[Math.floor(Math.random() * messagesPool.length)]
    });
  }
}
else if (scenario === 'FRAUD') {
  // --- 2 transactions guaranteed to hit the Hard Firewall (60M UZS) ---
  for (let i = 0; i < 2; i++) {
    payloadArray.push({
      user_id: generateUserId(),
      amount: 60000000, 
      message: 'transfer'
    });
  }
  // --- 3 transactions that require Human-in-the-Loop Telegram Approval (25M UZS) ---
  for (let i = 0; i < 3; i++) {
    payloadArray.push({
      user_id: generateUserId(),
      amount: 25000000, 
      message: 'urgent transfer'
    });
  }
}
else if (scenario === 'FAILED_PAYMENT') {
  // --- 3 failed refund scenarios ---
  for (let i = 0; i < 3; i++) {
    payloadArray.push({
      user_id: generateUserId(),
      amount: 150000,
      message: 'failed refund'
    });
  }
}
else {
  // Unknown scenario – return empty or a fallback? We'll return one generic item to avoid breaking.
  payloadArray.push({
    user_id: 'UNKNOWN',
    amount: 0,
    message: 'unknown scenario'
  });
}

// ============================================================
// 2. Map each item into an n8n compatible output
//    This ensures the next HTTP Request node processes
//    each payload individually.
// ============================================================
// --- HOW TO CONNECT TO PHASE 1 WEBHOOK ---
// After this node, add an "HTTP Request" node.
// Method: POST
// URL: <your_phase1_webhook_url>
// Body Content Type: JSON
// Body (using expressions):
//   {
//     "user_id": "{{ $json.user_id }}",
//     "amount": {{ $json.amount }},
//     "message": "{{ $json.message }}"
//   }
// The node will automatically loop through all generated items.
// ------------------------------------------

return payloadArray.map(item => ({ json: item }));
